from __future__ import annotations

from temporalio import activity


@activity.defn
def release_resources(job_id: str) -> None:
    with open("/workspace/cleanup.log", "a", encoding="utf-8") as log_file:
        log_file.write(f"released:{job_id}\n")

from __future__ import annotations

import asyncio
from datetime import timedelta

from temporalio import workflow

with workflow.unsafe.imports_passed_through():
    from activities import release_resources


@workflow.defn
class LongJobWorkflow:
    @workflow.run
    async def run(self, job_id: str) -> None:
        try:
            await workflow.sleep(timedelta(minutes=10))
        except asyncio.CancelledError:
            await asyncio.shield(
                workflow.execute_activity(
                    release_resources,
                    job_id,
                    start_to_close_timeout=timedelta(seconds=30),
                )
            )
            raise
